200→var skillsWriteCmd = &cobra.Command{
201→	Use:   "write",
202→	Short: "Write multiple skill files from stdin (one CLI call instead of many file writes)",
203→	Long: `Reads a JSON array from stdin: [{"name": "outbound", "content": "---\nname: nurge-outbound\n..."}]
204→Writes each as .claude/skills/nurge-{name}/SKILL.md.
205→Also saves each version to the database for tracking.
206→Returns a compact summary instead of echoing all file contents back.`,
207→	RunE: func(cmd *cobra.Command, args []string) error {
208→		var entries []skillEntry
209→		if err := json.NewDecoder(os.Stdin).Decode(&entries); err != nil {
210→			return fmt.Errorf("parsing stdin: %w", err)
211→		}
212→		if len(entries) == 0 {
213→			return fmt.Errorf("no skills provided")
214→		}
215→
216→		// Write skill files to disk.
217→		var written []string
218→		for _, e := range entries {
219→			if e.Name == "" || e.Content == "" {
220→				return fmt.Errorf("each skill must have 'name' and 'content' fields")
221→			}
222→			name := e.Name
223→			// Normalize: allow both "outbound" and "nurge-outbound".
224→			if !strings.HasPrefix(name, "nurge-") {
225→				name = "nurge-" + name
226→			}
227→
228→			dir := filepath.Join(".claude", "skills", name)
229→			if err := os.MkdirAll(dir, 0755); err != nil {
230→				return fmt.Errorf("creating dir %s: %w", dir, err)
231→			}
232→			path := filepath.Join(dir, "SKILL.md")
233→			if err := os.WriteFile(path, []byte(e.Content), 0644); err != nil {
234→				return fmt.Errorf("writing %s: %w", path, err)
235→			}
236→			written = append(written, name)
237→		}
238→
239→		// Save versions to DB if available.
240→		d, err := db.Open()
241→		if err == nil {
242→			defer d.Close()
243→			counts, err := session.CurrentSnapshotCounts(d)
244→			if err == nil {
245→				for _, e := range entries {
246→					name := e.Name
247→					if !strings.HasPrefix(name, "nurge-") {
248→						name = "nurge-" + name
249→					}
250→					_, _ = session.SaveSkillVersion(d, name, e.Content, counts.EmailCount, counts.LearningCount)
251→				}
252→			}
253→		}
254→
255→		fmt.Printf("  ✓ Wrote %d skills: %s\n", len(written), strings.Join(written, ", "))
256→		return nil
257→	},
258→}
