264→	skillsStaleCmd.Flags().StringVar(&skillsFormat, "format", "", "Output format (json)")
265→	skillsStaleCmd.Flags().IntVar(&skillsLimit, "limit", 10, "Maximum number of stale skills to show")
266→
267→	skillsCmd.AddCommand(skillsListCmd)
268→	skillsCmd.AddCommand(skillsHistoryCmd)
269→	skillsCmd.AddCommand(skillsRollbackCmd)
270→	skillsCmd.AddCommand(skillsSaveCmd)
