276→func readSkillContent(path string) (string, error) {
277→	var data []byte
278→	var err error
279→	if strings.TrimSpace(path) != "" {
280→		data, err = os.ReadFile(path)
281→		if err != nil {
282→			return "", fmt.Errorf("reading skill content: %w", err)
283→		}
284→	} else {
285→		data, err = io.ReadAll(os.Stdin)
286→		if err != nil {
287→			return "", fmt.Errorf("reading stdin: %w", err)
288→		}
289→	}
290→
291→	content := strings.TrimSpace(string(data))
292→	if content == "" {
293→		return "", fmt.Errorf("no skill content provided")
294→	}
295→	return content, nil
296→}
