package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strconv"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/session"
)

var skillsCmd = &cobra.Command{
	Use:   "skills",
	Short: "Manage generated skills and their versions",
}

var skillsFormat string
var skillsFile string
var skillsLimit int

var skillsListCmd = &cobra.Command{
	Use:   "list",
	Short: "List all skills with version info",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		skills, err := session.ListSkills(d)
		if err != nil {
			return err
		}

		if skillsFormat == "json" {
			return session.PrintJSON(skills)
		}

		if len(skills) == 0 {
			fmt.Println("No skills tracked yet.")
			return nil
		}

		for _, s := range skills {
			fmt.Printf("%-25s v%d (%d versions, updated %s)\n",
				s.SkillName, s.ActiveVersion, s.TotalVersions, s.LastUpdated)
		}
		return nil
	},
}

var skillsHistoryCmd = &cobra.Command{
	Use:   "history <skill-name>",
	Short: "Show version history for a skill",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		skillName := args[0]

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		versions, err := session.SkillHistory(d, skillName)
		if err != nil {
			return err
		}

		if skillsFormat == "json" {
			return session.PrintJSON(versions)
		}

		if len(versions) == 0 {
			fmt.Printf("No versions found for skill: %s\n", skillName)
			return nil
		}

		for _, v := range versions {
			active := " "
			if v.Active {
				active = "*"
			}
			fmt.Printf("%s v%d  %s  (emails: %d, learnings: %d)\n",
				active, v.Version, v.CreatedAt, v.EmailCount, v.LearningCount)
		}
		return nil
	},
}

var skillsRollbackCmd = &cobra.Command{
	Use:   "rollback <skill-name> <version>",
	Short: "Restore a previous skill version",
	Args:  cobra.ExactArgs(2),
	RunE: func(cmd *cobra.Command, args []string) error {
		skillName := args[0]
		version, err := strconv.Atoi(args[1])
		if err != nil {
			return fmt.Errorf("version must be a number: %w", err)
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := session.RollbackSkill(d, skillName, version); err != nil {
			return err
		}

		fmt.Printf("Rolled back %s to v%d\n", skillName, version)
		return nil
	},
}

var skillsSaveCmd = &cobra.Command{
	Use:   "save <skill-name>",
	Short: "Save a generated skill version from stdin or a file",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		skillName := args[0]

		content, err := readSkillContent(skillsFile)
		if err != nil {
			return err
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		counts, err := session.CurrentSnapshotCounts(d)
		if err != nil {
			return err
		}

		version, err := session.SaveSkillVersion(d, skillName, content, counts.EmailCount, counts.LearningCount)
		if err != nil {
			return err
		}

		fmt.Printf("Saved %s as v%d (emails: %d, learnings: %d)\n", skillName, version, counts.EmailCount, counts.LearningCount)
		return nil
	},
}

var skillsStaleCmd = &cobra.Command{
	Use:   "stale",
	Short: "List skills that likely need regeneration",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		items, err := session.ListStaleSkills(d, skillsLimit)
		if err != nil {
			return err
		}

		if skillsFormat == "json" {
			return session.PrintJSON(items)
		}

		if len(items) == 0 {
			fmt.Println("No skills need regeneration right now.")
			return nil
		}

		for _, item := range items {
			versionLabel := "untracked"
			if item.ActiveVersion > 0 {
				versionLabel = fmt.Sprintf("v%d", item.ActiveVersion)
			}
			fmt.Printf("%-25s %s\n", item.SkillName, versionLabel)
			for _, reason := range item.Reasons {
				fmt.Printf("  - %s\n", reason)
			}
		}
		return nil
	},
}

// skillEntry is the JSON input format for `skills write --stdin`.
type skillEntry struct {
	Name    string `json:"name"`
	Content string `json:"content"`
}

var skillsWriteCmd = &cobra.Command{
	Use:   "write",
	Short: "Write multiple skill files from stdin (one CLI call instead of many file writes)",
	Long: `Reads a JSON array from stdin: [{"name": "outbound", "content": "---\nname: nurge-outbound\n..."}]
Writes each as .claude/skills/nurge-{name}/SKILL.md.
Also saves each version to the database for tracking.
Returns a compact summary instead of echoing all file contents back.`,
	RunE: func(cmd *cobra.Command, args []string) error {
		var entries []skillEntry
		if err := json.NewDecoder(os.Stdin).Decode(&entries); err != nil {
			return fmt.Errorf("parsing stdin: %w", err)
		}
		if len(entries) == 0 {
			return fmt.Errorf("no skills provided")
		}

		// Write skill files to disk.
		var written []string
		for _, e := range entries {
			if e.Name == "" || e.Content == "" {
				return fmt.Errorf("each skill must have 'name' and 'content' fields")
			}
			name := e.Name
			// Normalize: allow both "outbound" and "nurge-outbound".
			if !strings.HasPrefix(name, "nurge-") {
				name = "nurge-" + name
			}

			dir := filepath.Join(".claude", "skills", name)
			if err := os.MkdirAll(dir, 0755); err != nil {
				return fmt.Errorf("creating dir %s: %w", dir, err)
			}
			path := filepath.Join(dir, "SKILL.md")
			if err := os.WriteFile(path, []byte(e.Content), 0644); err != nil {
				return fmt.Errorf("writing %s: %w", path, err)
			}
			written = append(written, name)
		}

		// Save versions to DB if available.
		d, err := db.Open()
		if err == nil {
			defer d.Close()
			counts, err := session.CurrentSnapshotCounts(d)
			if err == nil {
				for _, e := range entries {
					name := e.Name
					if !strings.HasPrefix(name, "nurge-") {
						name = "nurge-" + name
					}
					_, _ = session.SaveSkillVersion(d, name, e.Content, counts.EmailCount, counts.LearningCount)
				}
			}
		}

		fmt.Printf("  ✓ Wrote %d skills: %s\n", len(written), strings.Join(written, ", "))
		return nil
	},
}

func init() {
	skillsListCmd.Flags().StringVar(&skillsFormat, "format", "", "Output format (json)")
	skillsHistoryCmd.Flags().StringVar(&skillsFormat, "format", "", "Output format (json)")
	skillsSaveCmd.Flags().StringVar(&skillsFile, "file", "", "Read skill content from a file instead of stdin")
	skillsStaleCmd.Flags().StringVar(&skillsFormat, "format", "", "Output format (json)")
	skillsStaleCmd.Flags().IntVar(&skillsLimit, "limit", 10, "Maximum number of stale skills to show")

	skillsCmd.AddCommand(skillsListCmd)
	skillsCmd.AddCommand(skillsHistoryCmd)
	skillsCmd.AddCommand(skillsRollbackCmd)
	skillsCmd.AddCommand(skillsSaveCmd)
	skillsCmd.AddCommand(skillsStaleCmd)
	skillsCmd.AddCommand(skillsWriteCmd)
	rootCmd.AddCommand(skillsCmd)
}

func readSkillContent(path string) (string, error) {
	var data []byte
	var err error
	if strings.TrimSpace(path) != "" {
		data, err = os.ReadFile(path)
		if err != nil {
			return "", fmt.Errorf("reading skill content: %w", err)
		}
	} else {
		data, err = io.ReadAll(os.Stdin)
		if err != nil {
			return "", fmt.Errorf("reading stdin: %w", err)
		}
	}

	content := strings.TrimSpace(string(data))
	if content == "" {
		return "", fmt.Errorf("no skill content provided")
	}
	return content, nil
}

