package update

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

const (
	repo     = "usenurge/nurge"
	cacheTTL = 1 * time.Hour
)

// UpdateInfo holds information about an available update.
type UpdateInfo struct {
	CurrentVersion string `json:"current_version"`
	LatestVersion  string `json:"latest_version"`
	ReleaseURL     string `json:"release_url"`
}

// cacheEntry is the on-disk cache format.
type cacheEntry struct {
	LatestVersion string    `json:"latest_version"`
	ReleaseURL    string    `json:"release_url"`
	CheckedAt     time.Time `json:"checked_at"`
}

// githubRelease is the minimal GitHub API response we need.
type githubRelease struct {
	TagName string `json:"tag_name"`
	HTMLURL string `json:"html_url"`
}

// CheckForUpdate checks if a newer version is available.
// Returns nil if already up to date or on error.
func CheckForUpdate(ctx context.Context, currentVersion string) (*UpdateInfo, error) {
	// Try cache first.
	if cached, err := readCache(); err == nil && cached != nil {
		if time.Since(cached.CheckedAt) < cacheTTL {
			if isNewer(currentVersion, cached.LatestVersion) {
				return &UpdateInfo{
					CurrentVersion: currentVersion,
					LatestVersion:  cached.LatestVersion,
					ReleaseURL:     cached.ReleaseURL,
				}, nil
			}
			return nil, nil
		}
	}

	// Cache miss or stale — hit GitHub API.
	latest, err := fetchLatestRelease(ctx)
	if err != nil {
		return nil, err
	}

	// Write cache (best effort).
	_ = writeCache(&cacheEntry{
		LatestVersion: latest.TagName,
		ReleaseURL:    latest.HTMLURL,
		CheckedAt:     time.Now(),
	})

	if isNewer(currentVersion, latest.TagName) {
		return &UpdateInfo{
			CurrentVersion: currentVersion,
			LatestVersion:  latest.TagName,
			ReleaseURL:     latest.HTMLURL,
		}, nil
	}
	return nil, nil
}

// fetchLatestRelease gets the latest release from GitHub.
func fetchLatestRelease(ctx context.Context) (*githubRelease, error) {
	url := fmt.Sprintf("https://api.github.com/repos/%s/releases/latest", repo)
	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return nil, err
	}
	req.Header.Set("Accept", "application/vnd.github+json")

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("GitHub API returned %d", resp.StatusCode)
	}

	var release githubRelease
	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
		return nil, err
	}
	return &release, nil
}

// cacheDir returns ~/.nurge/, creating it if needed.
func cacheDir() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	dir := filepath.Join(home, ".nurge")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return "", err
	}
	return dir, nil
}

func cachePath() (string, error) {
	dir, err := cacheDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(dir, "update-check.json"), nil
}

func readCache() (*cacheEntry, error) {
	path, err := cachePath()
	if err != nil {
		return nil, err
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	var entry cacheEntry
	if err := json.Unmarshal(data, &entry); err != nil {
		return nil, err
	}
	return &entry, nil
}

func writeCache(entry *cacheEntry) error {
	path, err := cachePath()
	if err != nil {
		return err
	}
	data, err := json.Marshal(entry)
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0644)
}

// isNewer returns true if latest is a newer version than current.
// Both may have a "v" prefix.
func isNewer(current, latest string) bool {
	cur := parseVersion(current)
	lat := parseVersion(latest)
	if cur == nil || lat == nil {
		return false
	}
	for i := 0; i < 3; i++ {
		if lat[i] > cur[i] {
			return true
		}
		if lat[i] < cur[i] {
			return false
		}
	}
	return false
}

// parseVersion extracts [major, minor, patch] from a version string.
// Strips "v" prefix and ignores anything after a hyphen (prerelease).
func parseVersion(v string) []int {
	v = strings.TrimPrefix(v, "v")
	// Strip prerelease suffix (e.g., "0.1.3-alpha" → "0.1.3").
	if idx := strings.Index(v, "-"); idx >= 0 {
		v = v[:idx]
	}
	parts := strings.Split(v, ".")
	if len(parts) != 3 {
		return nil
	}
	nums := make([]int, 3)
	for i, p := range parts {
		n, err := strconv.Atoi(p)
		if err != nil {
			return nil
		}
		nums[i] = n
	}
	return nums
}

