package update

import (
	"archive/tar"
	"compress/gzip"
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"runtime"
	"strings"
)

// githubAsset is a release asset from the GitHub API.
type githubAsset struct {
	Name               string `json:"name"`
	BrowserDownloadURL string `json:"browser_download_url"`
}

// githubReleaseWithAssets extends githubRelease with asset info.
type githubReleaseWithAssets struct {
	TagName string        `json:"tag_name"`
	HTMLURL string        `json:"html_url"`
	Assets  []githubAsset `json:"assets"`
}

// SelfUpdate downloads and replaces the current binary with the target version.
// If targetVersion is empty, it updates to the latest release.
func SelfUpdate(ctx context.Context, currentVersion, targetVersion string, prerelease bool) error {
	release, err := fetchRelease(ctx, targetVersion, prerelease)
	if err != nil {
		return err
	}

	version := strings.TrimPrefix(release.TagName, "v")
	currentClean := strings.TrimPrefix(currentVersion, "v")
	if version == currentClean {
		fmt.Printf("✓ Already on latest version (v%s)\n", version)
		return nil
	}

	osName := runtime.GOOS
	arch := runtime.GOARCH

	if osName == "windows" {
		return fmt.Errorf("self-update is not supported on Windows. Please re-run the install script:\n  curl -fsSL https://install.nurge.sh | bash")
	}

	// Find the archive asset.
	archiveName := fmt.Sprintf("nurge_%s_%s_%s.tar.gz", version, osName, arch)
	var archiveURL string
	var checksumURL string
	for _, a := range release.Assets {
		if a.Name == archiveName {
			archiveURL = a.BrowserDownloadURL
		}
		if a.Name == "checksums.txt" {
			checksumURL = a.BrowserDownloadURL
		}
	}
	if archiveURL == "" {
		return fmt.Errorf("no release asset found for %s/%s in %s", osName, arch, release.TagName)
	}

	fmt.Printf("→ Downloading nurge v%s (%s/%s)...\n", version, osName, arch)

	// Download to temp dir.
	tmpDir, err := os.MkdirTemp("", "nurge-update-*")
	if err != nil {
		return err
	}
	defer os.RemoveAll(tmpDir)

	archivePath := filepath.Join(tmpDir, archiveName)
	if err := downloadFile(ctx, archiveURL, archivePath); err != nil {
		return fmt.Errorf("download failed: %w", err)
	}

	// Verify checksum if available.
	if checksumURL != "" {
		fmt.Println("→ Verifying checksum...")
		if err := verifyChecksum(ctx, checksumURL, archivePath, archiveName); err != nil {
			return err
		}
	}

	// Extract binary.
	binaryPath, err := extractBinary(archivePath, tmpDir)
	if err != nil {
		return fmt.Errorf("extraction failed: %w", err)
	}

	// Replace current executable.
	execPath, err := os.Executable()
	if err != nil {
		return err
	}
	execPath, err = filepath.EvalSymlinks(execPath)
	if err != nil {
		return err
	}

	newPath := execPath + ".new"
	if err := copyFile(binaryPath, newPath); err != nil {
		return fmt.Errorf("failed to stage new binary: %w", err)
	}
	if err := os.Chmod(newPath, 0755); err != nil {
		os.Remove(newPath)
		return err
	}

	if err := os.Rename(newPath, execPath); err != nil {
		os.Remove(newPath)
		if os.IsPermission(err) {
			return fmt.Errorf("permission denied: run sudo nurge update")
		}
		return fmt.Errorf("failed to replace binary: %w", err)
	}

	fmt.Printf("✓ Updated nurge to v%s (was %s)\n", version, currentVersion)

	// Write skill upgrade marker if we're in a nurge project.
	writePendingUpgradeMarker(currentVersion, release.TagName)

	return nil
}

// fetchRelease fetches a specific release or the latest.
func fetchRelease(ctx context.Context, targetVersion string, prerelease bool) (*githubReleaseWithAssets, error) {
	var url string
	if targetVersion != "" {
		// Ensure v prefix.
		if !strings.HasPrefix(targetVersion, "v") {
			targetVersion = "v" + targetVersion
		}
		url = fmt.Sprintf("https://api.github.com/repos/%s/releases/tags/%s", repo, targetVersion)
	} else if prerelease {
		// Fetch all releases and pick the first one (most recent, including prereleases).
		url = fmt.Sprintf("https://api.github.com/repos/%s/releases?per_page=1", repo)
	} else {
		url = fmt.Sprintf("https://api.github.com/repos/%s/releases/latest", repo)
	}

	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return nil, err
	}
	req.Header.Set("Accept", "application/vnd.github+json")

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode == http.StatusNotFound {
		return nil, fmt.Errorf("release not found: %s", targetVersion)
	}
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("GitHub API returned %d", resp.StatusCode)
	}

	if prerelease && targetVersion == "" {
		// The /releases endpoint returns an array.
		var releases []githubReleaseWithAssets
		if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
			return nil, err
		}
		if len(releases) == 0 {
			return nil, fmt.Errorf("no releases found")
		}
		return &releases[0], nil
	}

	var release githubReleaseWithAssets
	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
		return nil, err
	}
	return &release, nil
}

// downloadFile downloads a URL to a local path.
func downloadFile(ctx context.Context, url, dest string) error {
	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return err
	}

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("download returned %d", resp.StatusCode)
	}

	f, err := os.Create(dest)
	if err != nil {
		return err
	}
	defer f.Close()

	_, err = io.Copy(f, resp.Body)
	return err
}

// verifyChecksum downloads checksums.txt and verifies the archive.
func verifyChecksum(ctx context.Context, checksumURL, archivePath, archiveName string) error {
	// Download checksums.
	req, err := http.NewRequestWithContext(ctx, "GET", checksumURL, nil)
	if err != nil {
		return err
	}
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return fmt.Errorf("failed to download checksums: %w", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return err
	}

	// Parse checksums.txt — format: "sha256  filename"
	var expectedHash string
	for _, line := range strings.Split(string(body), "\n") {
		parts := strings.Fields(line)
		if len(parts) == 2 && parts[1] == archiveName {
			expectedHash = parts[0]
			break
		}
	}
	if expectedHash == "" {
		return fmt.Errorf("checksum not found for %s in checksums.txt", archiveName)
	}

	// Compute actual hash.
	f, err := os.Open(archivePath)
	if err != nil {
		return err
	}
	defer f.Close()

	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return err
	}
	actualHash := hex.EncodeToString(h.Sum(nil))

	if actualHash != expectedHash {
		return fmt.Errorf("checksum verification failed: expected %s, got %s — download may be corrupted, try again", expectedHash, actualHash)
	}
	return nil
}

// extractBinary extracts the nurge binary from a tar.gz archive.
func extractBinary(archivePath, destDir string) (string, error) {
	f, err := os.Open(archivePath)
	if err != nil {
		return "", err
	}
	defer f.Close()

	gz, err := gzip.NewReader(f)
	if err != nil {
		return "", err
	}
	defer gz.Close()

	tr := tar.NewReader(gz)
	for {
		hdr, err := tr.Next()
		if err == io.EOF {
			break
		}
		if err != nil {
			return "", err
		}
		if filepath.Base(hdr.Name) == "nurge" && hdr.Typeflag == tar.TypeReg {
			outPath := filepath.Join(destDir, "nurge")
			out, err := os.Create(outPath)
			if err != nil {
				return "", err
			}
			if _, err := io.Copy(out, tr); err != nil {
				out.Close()
				return "", err
			}
			out.Close()
			return outPath, nil
		}
	}
	return "", fmt.Errorf("nurge binary not found in archive")
}

// copyFile copies src to dst.
func copyFile(src, dst string) error {
	in, err := os.Open(src)
	if err != nil {
		return err
	}
	defer in.Close()

	out, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer out.Close()

	_, err = io.Copy(out, in)
	return err
}

// writePendingUpgradeMarker writes the skill upgrade marker if in a nurge project.
func writePendingUpgradeMarker(fromVersion, toVersion string) {
	// Check if .nurge/ directory exists (we're in a nurge project).
	if _, err := os.Stat(".nurge"); err != nil {
		return
	}

	marker := map[string]string{
		"from_version": fromVersion,
		"to_version":   toVersion,
		"updated_at":   strings.Replace(strings.Replace(fmt.Sprintf("%s", time.Now().UTC().Format(time.RFC3339)), " ", "T", 1), "+00:00", "Z", 1),
	}
	data, err := json.MarshalIndent(marker, "", "  ")
	if err != nil {
		return
	}
	_ = os.WriteFile(filepath.Join(".nurge", "pending-skill-upgrade.json"), data, 0644)
	fmt.Println("→ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.")
}

